import { defineStore } from 'pinia'
import { ref } from 'vue'
import { api } from '@/api'
import type { AgentState } from '@/types'

export const useAgentStore = defineStore('agent', () => {
  const agents = ref<AgentState[]>([])
  const loading = ref(false)

  const agentTypes = [
    { name: 'product-manager', displayName: '产品经理', type: 'product_manager' },
    { name: 'architect', displayName: '架构师', type: 'architect' },
    { name: 'ui-designer', displayName: 'UI设计', type: 'ui_designer' },
    { name: 'frontend', displayName: '前端', type: 'frontend' },
    { name: 'backend', displayName: '后端', type: 'backend' },
    { name: 'database', displayName: '数据库', type: 'database' },
    { name: 'tester', displayName: '测试', type: 'tester' },
    { name: 'security', displayName: '安全', type: 'security' },
    { name: 'documentation', displayName: '文档', type: 'documentation' },
    { name: 'assets', displayName: '素材', type: 'assets' }
  ]

  function initAgents() {
    agents.value = agentTypes.map(type => ({
      id: type.name,
      iterationId: 0,
      agentName: type.name,
      agentType: type.type,
      status: 'idle',
      currentTask: null,
      progress: 0,
      executionTimeSeconds: 0,
      apiCallsCount: 0,
      tokensUsed: 0,
      output: null,
      errorMessage: null,
      startedAt: null,
      completedAt: null,
      createdAt: new Date().toISOString()
    }))
  }

  async function fetchAgents() {
    loading.value = true
    try {
      const data = await api.getAgents()
      if (data && data.length > 0) {
        agents.value = data
      }
    } catch (error) {
      console.error('Failed to fetch agents:', error)
    } finally {
      loading.value = false
    }
  }

  function updateAgent(agentData: Partial<AgentState>) {
    const agent = agents.value.find(a => a.agentName === agentData.agentName)
    if (agent) {
      Object.assign(agent, agentData)
    }
  }

  function updateAgentProgress(agentName: string, progress: number) {
    const agent = agents.value.find(a => a.agentName === agentName)
    if (agent) {
      agent.progress = progress
    }
  }

  return {
    agents,
    loading,
    initAgents,
    fetchAgents,
    updateAgent,
    updateAgentProgress
  }
})
```

