#### 任务 2.3: 完善 Iteration Store（0.5 天）

**目标**: 管理迭代状态和历史

```typescript
// src/stores/iteration.ts
import { defineStore } from 'pinia'
import { ref, computed } from 'vue'
import type { IterationData } from '@/types'

export const useIterationStore = defineStore('iteration', () => {
  const currentIteration = ref<IterationData | null>(null)
  const iterations = ref<IterationData[]>([])
  const loading = ref(false)

  // 设置当前迭代
  function setCurrentIteration(iteration: IterationData) {
    currentIteration.value = iteration
  }

  // 更新当前迭代进度
  function updateProgress(progress: number) {
    if (currentIteration.value) {
      currentIteration.value.progress = progress
    }
  }

  // 更新当前迭代状态
  function updateStatus(status: IterationData['status']) {
    if (currentIteration.value) {
      currentIteration.value.status = status
      if (status === 'success' || status === 'failed') {
        // 迭代结束，添加到历史
        iterations.value.unshift({ ...currentIteration.value })
        currentIteration.value = null
      }
    }
  }

  // 添加迭代到历史
  function addIteration(iteration: IterationData) {
    iterations.value.unshift(iteration)
  }

  // 获取成功率
  const successRate = computed(() => {
    const total = iterations.value.length
    if (total === 0) return 0
    const success = iterations.value.filter(i => i.status === 'success').length
    return (success / total) * 100
  })

  // 获取平均执行时间
  const avgDuration = computed(() => {
    const completed = iterations.value.filter(i => i.duration)
    if (completed.length === 0) return 0
    const total = completed.reduce((sum, i) => sum + (i.duration || 0), 0)
    return total / completed.length
  })

  return {
    currentIteration,
    iterations,
    loading,
    successRate,
    avgDuration,
    setCurrentIteration,
    updateProgress,
    updateStatus,
    addIteration
  }
})
```

