<script setup lang="ts">
import { ref, computed, onMounted } from 'vue'
import { useIterationStore } from '@/stores/iteration'
import { ElMessage, ElMessageBox } from 'element-plus'
import IterationDetailDialog from '@/components/IterationDetailDialog.vue'

const iterationStore = useIterationStore()

const searchKeyword = ref('')
const statusFilter = ref('')
const dateRange = ref<[Date, Date]>()
const currentPage = ref(1)
const pageSize = ref(20)
const loading = ref(false)
const detailVisible = ref(false)
const selectedIteration = ref<IterationData | null>(null)

const total = computed(() => iterationStore.iterations.length)

const filteredIterations = computed(() => {
  let list = iterationStore.iterations

  // 关键词搜索
  if (searchKeyword.value) {
    list = list.filter(i => 
      i.requirement.includes(searchKeyword.value)
    )
  }

  // 状态筛选
  if (statusFilter.value) {
    list = list.filter(i => i.status === statusFilter.value)
  }

  // 日期筛选
  if (dateRange.value && dateRange.value.length === 2) {
    const [start, end] = dateRange.value
    list = list.filter(i => {
      const date = new Date(i.createdAt)
      return date >= start && date <= end
    })
  }

  // 分页
  const start = (currentPage.value - 1) * pageSize.value
  const end = start + pageSize.value
  return list.slice(start, end)
})

function getStatusType(status: string) {
  const map = {
    running: 'primary',
    success: 'success',
    failed: 'danger',
    pending: 'info'
  }
  return map[status] || 'info'
}

function getStatusText(status: string) {
  const map = {
    running: '运行中',
    success: '成功',
    failed: '失败',
    pending: '等待中'
  }
  return map[status] || status
}

function formatDuration(seconds: number) {
  if (!seconds) return '-'
  const minutes = Math.floor(seconds / 60)
  const secs = seconds % 60
  return `${minutes}m ${secs}s`
}

function formatTime(date: string) {
  return new Date(date).toLocaleString('zh-CN')
}

function showDetail(iteration: IterationData) {
  selectedIteration.value = iteration
  detailVisible.value = true
}

async function rollback(iteration: IterationData) {
  try {
    await ElMessageBox.confirm(
      `确定要回滚到迭代 #${iteration.iterationNumber} 吗？`,
      '确认回滚',
      {
        type: 'warning',
        confirmButtonText: '确定',
        cancelButtonText: '取消'
      }
    )

    // 调用回滚 API
    // await rollbackIteration(iteration.id)

    ElMessage.success('回滚成功')
  } catch {
    // 用户取消
  }
}

async function loadIterations() {
  loading.value = true
  try {
    // 从 API 加载迭代历史
    // const data = await fetchIterations({
    //   page: currentPage.value,
    //   pageSize: pageSize.value,
    //   status: statusFilter.value
    // })
    // iterationStore.iterations = data
  } finally {
    loading.value = false
  }
}

onMounted(() => {
  loadIterations()
})
</script>

