#### 任务 7.2: AutoIterationEngine 集成（1 天）

```typescript
// src/auto-iteration.ts
import { getServices } from './dashboard/server'

export class AutoIterationEngine {
  private iterationService: IterationService
  private realtimeService: RealtimeService

  constructor() {
    const services = getServices()
    this.iterationService = services.iterationService
    this.realtimeService = services.realtimeService
  }

  async start() {
    // 创建迭代记录
    const iteration = await this.iterationService.create({
      iterationNumber: this.count,
      status: 'running',
      requirement: this.requirement
    })

    // 推送迭代开始事件
    this.realtimeService.broadcast('iteration.started', iteration)

    // 执行产品经理 Agent
    await this.runAgent('product_manager', {
      task: '分析需求',
      requirement: this.requirement
    })

    this.realtimeService.broadcast('iteration.progress', {
      iterationId: iteration.id,
      progress: 10,
      phase: 'product_manager'
    })

    // 继续执行其他 Agent...
  }

  private async runAgent(name: string, task: any) {
    this.realtimeService.broadcast('agent.status_changed', {
      name,
      status: 'running',
      currentTask: task.task
    })

    try {
      // 执行 Agent
      const result = await this.executeAgent(name, task)

      this.realtimeService.broadcast('agent.status_changed', {
        name,
        status: 'success'
      })

      return result
    } catch (error) {
      this.realtimeService.broadcast('agent.status_changed', {
        name,
        status: 'error',
        error: error.message
      })
      throw error
    }
  }
}
```

