```typescript
// src/dashboard/server.ts

export async function startDashboard(config: DashboardConfig) {
  const server = fastify();

  // 注册 WebSocket
  await server.register(fastifyWebSocket);

  // WebSocket 路由
  server.register(async function (fastify) {
    fastify.get('/ws', { websocket: true }, (connection, req) => {
      const connectionId = generateId();

      console.log(`✅ WebSocket 连接: ${connectionId}`);

      // 发送连接确认
      connection.socket.send(JSON.stringify({
        type: 'connected',
        data: { connectionId },
        timestamp: new Date().toISOString()
      }));

      // 消息处理
      connection.socket.on('message', (message: string) => {
        try {
          const data = JSON.parse(message.toString());
          handleMessage(connectionId, data, connection.socket);
        } catch (error) {
          console.error('消息解析错误:', error);
        }
      });

      // 心跳检测
      const heartbeatInterval = setInterval(() => {
        if (connection.socket.readyState === 1) {
          connection.socket.send(JSON.stringify({
            type: 'ping',
            timestamp: new Date().toISOString()
          }));
        } else {
          clearInterval(heartbeatInterval);
        }
      }, 30000);

      // 连接关闭
      connection.socket.on('close', () => {
        console.log(`❌ WebSocket 断开: ${connectionId}`);
        clearInterval(heartbeatInterval);
        removeConnection(connectionId);
      });
    });
  });

  return server;
}

// 消息处理
function handleMessage(
  connectionId: string, 
  message: any, 
  socket: WebSocket
) {
  const { type, channel } = message;

  switch (type) {
    case 'subscribe':
      // 订阅频道
      subscribe(connectionId, channel);
      console.log(`📡 ${connectionId} 订阅 ${channel}`);
      break;

    case 'unsubscribe':
      // 取消订阅
      unsubscribe(connectionId, channel);
      console.log(`📡 ${connectionId} 取消订阅 ${channel}`);
      break;

    case 'pong':
      // 心跳响应
      updateHeartbeat(connectionId);
      break;

    default:
      console.warn(`未知消息类型: ${type}`);
  }
}
