**任务 1.3: 频道管理器实现** ⏰ 30分钟
```typescript
// src/dashboard/services/channel-manager.ts

export class ChannelManager {
  private subscriptions: Map<string, Set<string>> = new Map();
  private connections: Map<string, WebSocket> = new Map();

  // 添加连接
  addConnection(connectionId: string, socket: WebSocket) {
    this.connections.set(connectionId, socket);
  }

  // 移除连接
  removeConnection(connectionId: string) {
    // 清理所有订阅
    for (const [channel, subscribers] of this.subscriptions.entries()) {
      subscribers.delete(connectionId);
    }
    this.connections.delete(connectionId);
  }

  // 订阅频道
  subscribe(connectionId: string, channel: string) {
    if (!this.subscriptions.has(channel)) {
      this.subscriptions.set(channel, new Set());
    }
    this.subscriptions.get(channel)!.add(connectionId);
  }

  // 取消订阅
  unsubscribe(connectionId: string, channel: string) {
    const subscribers = this.subscriptions.get(channel);
    if (subscribers) {
      subscribers.delete(connectionId);
    }
  }

  // 获取频道订阅者
  getSubscribers(channel: string): Set<string> {
    return this.subscriptions.get(channel) || new Set();
  }

  // 广播到频道
  broadcastToChannel(channel: string, message: any) {
    const subscribers = this.getSubscribers(channel);
    const payload = JSON.stringify(message);

    subscribers.forEach(connectionId => {
      const socket = this.connections.get(connectionId);
      if (socket && socket.readyState === 1) {
        socket.send(payload);
      }
    });
  }

  // 广播到所有连接
  broadcast(message: any) {
    const payload = JSON.stringify(message);

    this.connections.forEach((socket) => {
      if (socket.readyState === 1) {
        socket.send(payload);
      }
    });
  }
}
```

