    metrics.value = newMetrics;
  }

  return {
    metrics,
    updateMetrics
  };
});

// dashboard/src/stores/log.ts

export const useLogStore = defineStore('log', () => {
  const logs = ref<LogEntry[]>([]);
  const maxLogs = 1000;

  // ✅ WebSocket 实时添加
  function addLogEntry(log: LogEntry) {
    logs.value.push(log);

    // 限制日志数量
    if (logs.value.length > maxLogs) {
      logs.value.shift();
    }
  }

  return {
    logs,
    addLogEntry
  };
});
